#include "game/progression/EquipmentSystem.h"
namespace fw { bool EquipmentSystem::EquipFirstMatching(SaveGameProfile& profile, const ItemDatabase& itemDb, const std::string& slot) const { for(const auto& itemId: profile.inventory.items){ const auto* item=itemDb.Find(itemId); if(!item) continue; if(item->equipSlot==slot){ if(slot=="weapon") profile.inventory.equippedWeaponId=itemId; else if(slot=="armor") profile.inventory.equippedArmorId=itemId; return true; } } return false; } bool EquipmentSystem::UseFirstConsumable(SaveGameProfile& profile, const ItemDatabase& itemDb) const { for(size_t i=0;i<profile.inventory.items.size();++i){ const auto* item=itemDb.Find(profile.inventory.items[i]); if(!item) continue; if(item->type=="consumable"&&item->heal>0){ profile.playerHealth+=item->heal; if(profile.playerHealth>profile.playerMaxHealth) profile.playerHealth=profile.playerMaxHealth; profile.inventory.items.erase(profile.inventory.items.begin()+i); return true; } } return false; } }
